import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface VaccinationSummary {
  totalDosesReceived: number;
  nextDoseDueDate: string;
  coveragePercentage: number;
}

interface DoseHistory {
  doseNumber: number;
  dateReceived: string;
  vaccineType: string;
}

interface VaccinationData {
  vaccinationSummary: VaccinationSummary;
  doseHistory: DoseHistory[];
}

export default function Widget() {
  const vaccinationData = response.data as VaccinationData;
  const { vaccinationSummary, doseHistory } = vaccinationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC' }}>
              Vaccination Tracker
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Total Doses Received: {vaccinationSummary.totalDosesReceived}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Next Dose Due: {vaccinationSummary.nextDoseDueDate}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Coverage: {vaccinationSummary.coveragePercentage}%
            </Typography>
          </Box>

          <Box>
            <Typography variant="subtitle1" sx={{ color: '#F8FAFC', mb: 1 }}>
              Dose History
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {doseHistory.map((dose) => (
                <Chip
                  key={dose.doseNumber}
                  label={`Dose ${dose.doseNumber}: ${dose.dateReceived} (${dose.vaccineType})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#334155', color: '#F8FAFC' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
